                          <TableHead className="text-xs">番号</TableHead>
                          <TableHead className="text-xs">あたり</TableHead>
                          <TableHead
                            className="text-right text-xs"
                            title={ENSEMBLE_SCORE_HEAD_TITLE}
                          >
