}

/** v16: セット購入プラン表示 */
function SetPlanCard({
  title,
  plan,
  winning: winningRaw,
}: {
  title: string;
  plan: SetPlanPayload | undefined;
  winning: string | null;
}) {
  const recs = plan?.recommendations ?? [];
  if (!plan || recs.length === 0) return null;

  return (
