}: {
  simulation: MonthlySimulationPayload | undefined;
}) {
  if (!simulation?.strategies?.length) return null;

  return (
    <Card className="border-border/80 shadow-sm ring-1 ring-black/5 dark:ring-white/10 lg:col-span-2">
